-- =====================================================================
-- Hyjal (map 750)  --  Neltharion spawn-layer migration
-- ---------------------------------------------------------------------
-- Replaces the cata-sourced spawn layer with Project Neltharion 4.3.4's (richer
-- placement, 13 waypoint routes, pool-gating, per-spawn MovementType). Templates,
-- quests, loot, gossip stay as the cata dc-clone (id = nelt_id + 3600000). Only base-
-- visible spawns (phaseMask&1). Guid blocks: creature +12000000, gameobject +12500000, waypoint
-- +130000000, pool +130000000. Apply AFTER 01-13 (templates must exist). Idempotent.
-- =====================================================================

-- Drop ONLY the shared-template cata spawns (nelt re-adds them) + the prior Nel block.
-- The cata-only NPCs (templates nelt does not spawn) keep their cata spawns.
DELETE FROM `creature`        WHERE `map`=750 AND `guid`<12000000 AND `id` IN (3606491,3607446,3610201,3613148,3614348,3635374,3636198,3636286,3636911,3638896,3638902,3638913,3638915,3638917,3638926,3638934,3638952,3639391,3639406,3639412,3639413,3639427,3639429,3639437,3639442,3639451,3639588,3639600,3639618,3639619,3639621,3639637,3639658,3639726,3639752,3639765,3639828,3639833,3639843,3639844,3639846,3639857,3639859,3639869,3639879,3639919,3639921,3639925,3639927,3639928,3639929,3639930,3639931,3639933,3639939,3639941,3640031,3640034,3640066,3640123,3640139,3640140,3640178,3640185,3640229,3640242,3640254,3640278,3640289,3640403,3640409,3640412,3640463,3640464,3640489,3640491,3640536,3640540,3640557,3640578,3640619,3640650,3640687,3640709,3640713,3640720,3640723,3640755,3640757,3640762,3640767,3640803,3640812,3640814,3640819,3640833,3640834,3640837,3640838,3640841,3640843,3640844,3640845,3640868,3640882,3640931,3640998,3641004,3641008,3641027,3641028,3641200,3641300,3641308,3641492,3641497,3641498,3641499,3641500,3641502,3641504,3641507,3641509,3641557,3641563,3641565,3641614,3641860,3641861,3641959,3642657,3642658,3642659,3642660,3642663,3642664,3642668,3643378,3643379,3643381,3643408,3643410,3643411,3643427,3643481,3643494,3643495,3643563,3643564,3643565,3644775,3646925,3646974,3647263,3647264,3647459,3649444,3649445,3649456,3649759,3650053,3650055,3650056,3650057,3650058,3650070,3650079,3650083,3650314,3650419,3650485,3651682,3652995,3653493,3653697,3654168,3654171,3654172,3654173,3654174,3654175,3654176,3654177,3654178,3654179,3654180,3654312,3654313,3654318,3654319,3654320,3655227,3660461,3660463,3660465,3660467,3660469,3675004,3675005,3675012,3675013,3675014,3675015,3675019,3675020,3675021,3675023,3675026,3675027,3675028,3675030,3675031,3675032,3675036,3675158);
DELETE FROM `creature`        WHERE `guid` BETWEEN 12000000 AND 12499999;
DELETE FROM `creature_addon`  WHERE `guid` BETWEEN 12000000 AND 12499999;
DELETE FROM `gameobject`      WHERE `guid` BETWEEN 12500000 AND 12999999;
DELETE FROM `pool_creature`   WHERE `pool_entry` BETWEEN 130000000 AND 130999999;
DELETE FROM `pool_gameobject` WHERE `pool_entry` BETWEEN 130000000 AND 130999999;
DELETE FROM `pool_template`   WHERE `entry` BETWEEN 130000000 AND 130999999;
DELETE FROM `waypoint_data`   WHERE `id` BETWEEN 130000000 AND 130999999;








-- Orphan cleanup: drop nelt-only spawns whose +3600000 clone template we haven't imported yet
-- (the 119 Molten Front/Firelands NPCs — handled by the template-import phase), + dangling addon/pool.
DELETE c FROM `creature` c LEFT JOIN `creature_template` ct ON ct.`entry`=c.`id` WHERE c.`map`=750 AND c.`guid`>=12000000 AND ct.`entry` IS NULL;
DELETE g FROM `gameobject` g LEFT JOIN `gameobject_template` gt ON gt.`entry`=g.`id` WHERE g.`map`=750 AND g.`guid`>=12500000 AND gt.`entry` IS NULL;
DELETE a FROM `creature_addon` a LEFT JOIN `creature` c ON c.`guid`=a.`guid` WHERE a.`guid`>=12000000 AND c.`guid` IS NULL;
DELETE p FROM `pool_creature` p LEFT JOIN `creature` c ON c.`guid`=p.`guid` WHERE p.`pool_entry`>=130000000 AND c.`guid` IS NULL;
DELETE p FROM `pool_gameobject` p LEFT JOIN `gameobject` g ON g.`guid`=p.`guid` WHERE p.`pool_entry`>=130000000 AND g.`guid` IS NULL;
